update public.lessons l set enhancements = $ench${"industryStory":"A new hire needed to change the login page object and spent twenty minutes hunting for it in a flat folder of mixed files. A predictable structure — pages, tests, components, fixtures, utils, data — would have made it a five-second find. Structure is onboarding documentation.","visualAid":{"type":"comparison","title":"A sensible framework layout","headers":["Folder","Holds"],"rows":[["tests/","Specs, grouped by feature"],["pages/","Page objects"],["components/","Reusable component objects"],["fixtures/","Custom fixtures"],["utils/ · data/","Helpers · JSON/CSV data"]]},"davidTip":"Group files by concern so anyone can guess where something lives. If a newcomer can find the login page object without asking, your structure is working.","miniChallenge":"Sketch a folder structure for an automation framework with tests, pages, fixtures, utils and data.","modelAnswer":"## Example\n/tests (auth, checkout, account) · /pages (LoginPage, CheckoutPage) · /components (NavBar) · /fixtures (auth) · /utils (uniqueEmail) · /data (discounts.json).","resourcePreview":{"name":"Test Structure & Naming Conventions Guide","purpose":"Organise a framework so it stays navigable as it grows.","whenToUse":"Use it to lay out your capstone framework.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 7 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"The same timestamp-email logic was copy-pasted across a dozen tests. Extracting one uniqueEmail() helper removed the duplication and made the tests read clearly. Helpers, used well, keep tests focused.","davidTip":"Extract a helper when you see real repetition — not speculatively. And helpers should make tests clearer, not hide important logic: if a reader must open the helper to understand the test, reconsider it.","miniChallenge":"Identify one repeated snippet across tests and extract it into a well-named helper.","modelAnswer":"## Example\nRepeated \"user+Date.now()@example.com\" became uniqueEmail(); tests now call uniqueEmail() — shorter, clearer, and the logic lives in one place."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 7 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A team built a five-level class hierarchy for page objects \"for flexibility\" — and nobody could follow it. Replacing most of it with fixtures and a single thin BasePage made the framework far easier to understand. Composition beats deep inheritance.","davidTip":"Prefer fixtures and components over deep inheritance. One shallow BasePage (shared goto/wait helpers) is usually enough; deep class hierarchies obscure behaviour and trap maintainers.","miniChallenge":"Design a BasePage with one shared method your page objects could extend.","modelAnswer":"## Example\nclass BasePage { constructor(page){this.page=page} async goto(path){ await this.page.goto(path); } } — LoginPage and Dashboard extend it and add only their own specifics; shared state otherwise comes from fixtures."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'practical-test-automation-playwright'
  and m.module_number = 7 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"A CI failure had no artefacts, so an engineer debugged blind for an hour. Once the suite captured trace, screenshot and the HTML report on failure, the next failure was diagnosed from the report in minutes. Reporting turns failures into evidence.","davidTip":"Capture trace/screenshot on failure and publish the HTML report — it doubles as evidence for stakeholders. Log meaningful context (which data, which environment), not noise; let the trace carry the step detail.","miniChallenge":"Enable the HTML reporter and on-failure artefacts, force a failure, and review the report.","modelAnswer":"## Example\nConfig: reporter 'html', use: { trace:'on-first-retry', screenshot:'only-on-failure' }. A forced failure produced a report linking the trace and screenshot — cause clear without re-running."}$ench$::jsonb
